const FONT_LINK = 'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap';
const KATEX_CSS = 'https://cdnjs.cloudflare.com/ajax/libs/KaTeX/0.16.9/katex.min.css';
const KATEX_JS  = 'https://cdnjs.cloudflare.com/ajax/libs/KaTeX/0.16.9/katex.min.js';

function FontInjector() {
  React.useEffect(() => {
    const id = 'crrem-tool-fonts';
    if (!document.getElementById(id)) {
      const link = document.createElement('link');
      link.id = id; link.rel = 'stylesheet'; link.href = FONT_LINK;
      document.head.appendChild(link);
    }
    // KaTeX CSS
    const cssId = 'crrem-katex-css';
    if (!document.getElementById(cssId)) {
      const link = document.createElement('link');
      link.id = cssId; link.rel = 'stylesheet'; link.href = KATEX_CSS;
      document.head.appendChild(link);
    }
    // KaTeX JS (async — loaded once, then window.katex is available)
    const jsId = 'crrem-katex-js';
    if (!document.getElementById(jsId)) {
      const script = document.createElement('script');
      script.id = jsId; script.src = KATEX_JS; script.async = true;
      script.onload = () => _notifyKatexReady();
      document.head.appendChild(script);
    } else if (window.katex) {
      _notifyKatexReady();
    }
  }, []);
  return null;
}

// KaTeX readiness — components that call renderMath subscribe to this
let _katexReadyCallbacks = [];
let _katexReady = false;
function onKatexReady(cb) { if (_katexReady) cb(); else _katexReadyCallbacks.push(cb); }
function _notifyKatexReady() { _katexReady = true; _katexReadyCallbacks.forEach(cb => cb()); _katexReadyCallbacks = []; }

// Hook: returns true once KaTeX JS has loaded
function useKatexReady() {
  const [ready, setReady] = React.useState(_katexReady);
  React.useEffect(() => { if (!ready) onKatexReady(() => setReady(true)); }, []);
  return ready;
}

// Render a LaTeX string via KaTeX; falls back to monospace if not loaded yet
function renderMath(latex, displayMode = false) {
  try {
    if (window.katex) {
      const html = window.katex.renderToString(latex, { displayMode, throwOnError: false, output: 'html' });
      return <span dangerouslySetInnerHTML={{ __html: html }} />;
    }
  } catch (_) {}
  return <code style={{ fontFamily: 'monospace', fontSize: '0.9em' }}>{displayMode ? `$$${latex}$$` : `$${latex}$`}</code>;
}

