const STAGES = [
  { num: 1,  label: 'Data layer',            desc: 'CRREM reference data loaded; app shell built', status: 'done' },
  { num: 2,  label: 'Upload flow',            desc: 'CSV upload, paste-from-Excel for energy bills, validation engine', status: 'done' },
  { num: 3,  label: 'Calculation engine',     desc: 'Roll-up, normalisation, emission factor application, BAU forecast', status: 'done' },
  { num: 4,  label: 'Charts & CRREM comparison', desc: 'Stranding analysis, per-building breakdown, country/asset class filter', status: 'done' },
  { num: 5,  label: 'Retrofit modeller',      desc: 'Library + custom retrofits, scenario comparison', status: 'done' },
  { num: 6,  label: 'Property map',           desc: 'Leaflet map in Dashboard — pins colour-coded by stranding year, sized by selected metric (CI, tCO₂e, EI, total energy, EPC). Nominatim/OSM geocoding with persistent cache.', status: 'done' },
  { num: 7,  label: 'Advanced filters',       desc: 'Compound AND/OR filter builder — AND conditions on the same row, OR between row groups; applies across Dashboard, table, and charts', status: 'planned' },
  { num: 8,  label: 'Fuel tariffs (user-editable)', desc: 'The tool already infers utility bills from a hardcoded DEFAULT_TARIFFS table (Eurostat H2 2024, GlobalPetrolPrices, IEA) when no bills are uploaded, stamping them as inferred: true. The gap is editability: users cannot currently view, override, or extend those reference tariffs. This item adds a tariff settings panel where users can view the defaults per country and fuel, override individual rates, and add time-series rates (e.g. £0.28/kWh electricity 2024, £0.24 2025) to reflect forecast price paths. Tariff changes should re-derive all inferred bills in real time. Actual uploaded bills are never replaced. Tariffs are also the input for retrofit ROI calculations (item 9).', status: 'planned' },
  { num: 9,  label: 'Retrofit ROI',             desc: 'Per-building, per-measure payback calculated from actual fuel tariffs × modelled energy reduction × retrofit capital cost. Outputs simple payback period, NPV at a user-defined discount rate, and IRR. Displayed inline on the building assignment card and aggregated across the portfolio. Replaces the indicative payback ranges previously shown in the measure catalogue (removed — too coarse to be useful at building level).', status: 'planned' },
  { num: 10, label: 'Retrofit bulk assignment',  desc: 'Allow users to assign a measure to many buildings at once: (a) select buildings via checkbox in a table or map, then assign a measure and year to the whole selection; (b) rule-based auto-assign (e.g. "apply LED upgrade to all buildings where lighting_type ≠ led and stranding year < 2030"); (c) a portfolio-level measures panel showing every active measure–building pair in one scrollable table with inline year editing and bulk delete. Includes incompatibility warnings across the whole selection before committing.', status: 'partial' },
  { num: 11, label: 'Retrofit cost modelling',   desc: 'Flexible cost model per measure: (a) fixed lump sum (e.g. £50,000 for a specific building); (b) variable rate per m² of GIA (e.g. £8/m²); (c) formula-based (user enters an equation referencing building fields: e.g. gia * 8 + 2000). Cost model is set when defining or editing a measure and can be overridden per building assignment. Used by the ROI module to calculate capital outlay and payback.', status: 'partial' },
  { num: 12, label: 'Multi-currency support', desc: 'Let users work in £, $, or € across retrofit costs, utility bills, and ROI outputs. A global settings panel lets users define custom exchange rates; all monetary figures display in the selected currency.', status: 'partial' },
  { num: 13, label: 'CRREM emission factor sync', desc: 'Automated check against the CRREM data release feed; alerts the user when a new emission factor dataset is available and lets them apply it in one click, with a changelog showing what changed.', status: 'planned' },
  { num: 14, label: 'Emission factor viewer', desc: 'Dedicated view inside the Emission factors tab letting users browse all CRREM country × year electricity factors and any custom fuel factors, with CSV export for audit purposes.', status: 'done' },
  { num: 15, label: 'Energy normalisation switch', desc: 'Global toggle enabling/disabling all occupancy normalisations at once, so users can compare raw vs. normalised figures across charts, the table, and exports.', status: 'planned' },
  { num: 16, label: 'Composable dashboard',  desc: 'Users can select, deselect, and reorder charts and scorecards on the Dashboard using drag-and-drop. Layouts are saved per-session and can be exported and restored. Once user accounts are live (item 19), each user maintains their own named views — saved independently per account — so a fund manager and an asset manager looking at the same portfolio each see the layout that suits their workflow. Views can be shared with other users, who can adopt them as a starting point or keep their own.', status: 'done' },
  { num: 17, label: 'App tour & video guide', desc: 'An interactive step-by-step walkthrough that highlights each section of the tool on first launch (and on demand), plus an embedded short video guide for each major workflow.', status: 'planned' },
  { num: 18, label: 'Documentation',         desc: 'Dedicated Guide tab with two sections — User guide (step-by-step workflows, keyboard shortcuts, FAQ) and Methodology (formulas, assumptions, CRREM attribution, fuel types, retrofit model detail). Sticky left sidebar with section switcher and clickable table of contents. Embedded inline — no external fetch required.', status: 'done' },
  { num: 19, label: 'User accounts & data isolation', desc: 'Authentication layer (email/password + SSO) so each user sees only their own buildings, energy data, and bills. Data is scoped to the authenticated account at the database level — no cross-user leakage. Includes account settings, session management, and audit log. Each user also owns their own retrofit library and dashboard views (see items 16 and 20a); these are private by default and shareable on demand.', status: 'planned' },
  { num: 20, label: 'Building & portfolio sharing', desc: 'Owners can invite other users to individual buildings or whole portfolios via email. Recipients get a pending-share notification and can accept or decline. Accepted shares grant configurable access levels (view-only or edit). Shared buildings appear in a dedicated "Shared with me" section and are visually distinguished from owned buildings throughout the tool.', status: 'planned' },
  { num: '20a', label: 'Retrofit library sharing', desc: 'Each user owns a private retrofit measure library. Individual measures or entire libraries can be shared with specific users or made public to all users of the instance. Recipients can adopt a shared measure as-is or fork it into their own library to customise independently. Shared measures display the original author and version, so teams can maintain a canonical set of approved measures while allowing analysts to experiment in their own copies.', status: 'planned' },
  { num: '20b', label: 'Dashboard view sharing', desc: 'Once composable dashboards (item 16) and user accounts (item 19) are live, users can share saved dashboard layouts with colleagues. A shared view is delivered as a one-click link; the recipient can preview it and choose to save it to their own account. Views remember filter state, chart selection, and scorecard configuration — so sharing a view is a fast way to hand off a specific analytical perspective without re-building it from scratch.', status: 'planned' },
  { num: 21, label: 'Portfolio tags & tag-based grouping', desc: 'Free-form and structured tags applied at the building level (e.g. "Fund A", "Core strategy", "Disposal pipeline", "Green loan covenant"). Users can create, rename, and colour-code tags from a central tag manager. The Dashboard and table support filtering and grouping by one or more tags, letting users compose ad-hoc portfolios without duplicating building records. Tags are exportable alongside building data.', status: 'planned' },
  { num: 24, label: 'Review data validation', desc: 'Audit and unify validation logic across all data-entry sections — Portfolio, Energy, Occupancy, and Utility bills. Ensure consistent error/warning coverage: required fields, plausible ranges (e.g. kWh spikes vs prior month, cost vs kWh ratio sanity check), missing months, zero-value detection, and cross-section consistency (e.g. bill for a fuel type with no energy data). Add a global validation summary panel accessible from any tab. Consider inline suggestions (e.g. auto-detect likely unit errors — MWh entered as kWh).', status: 'planned' },
  { num: 23, label: 'Export data', desc: 'A dedicated export panel (or top-level button) that lets users download all session data in one go — portfolio, energy, occupancy, bills, and CRREM results — as a single ZIP containing clean CSVs, or as a formatted Excel workbook with one sheet per data type. Includes a CRREM results export (building-level CI, stranding year, exceedance %) and a dashboard summary export to PDF or PNG for reporting. Individual per-tab exports already exist; this consolidates them into a single action. Time-series exports (energy, occupancy, bills) are currently long-format (one row per building × month × fuel); the consolidated export should offer a wide-format option (one row per building, months as columns) for easier use in Excel and BI tools.', status: 'partial' },
  { num: 22, label: 'AI portfolio analyst', desc: 'Embedded AI assistant (Claude API) with three operating modes. (1) Data quality advisor: scans portfolio and energy data for anomalies — missing months, implausible EUI spikes, meter unit mismatches, occupied buildings with zero energy — and presents ranked issues with one-click corrections the user can accept or edit. (2) Portfolio analyst: interprets CRREM results in plain English, identifies worst-performing buildings by CI and stranding year, compares countries and asset classes, flags concentration risk, and surfaces insights the user might miss in the raw charts. (3) Retrofit recommender: given a building asset class, country, current EUI and stranding year, recommends measures from the user library or a built-in catalogue, estimates carbon and cost impact, and proposes an implementation sequence. The assistant has read-only access to portfolio, energy, bills and CRREM results and never modifies data without explicit user confirmation. Architecture: the assistant works by injecting a structured JSON summary of the session state (per-building annual aggregates of CI, stranding year, EUI, cost) into each API call as a system prompt — the model does not need to understand CRREM independently, it reasons over the numbers provided. Three UI components needed: (a) a floating chat panel (sidebar or bottom drawer), (b) a thin server-side /api/chat proxy endpoint that holds the Anthropic API key and never exposes it to the client, (c) a buildContext() function that serialises current session state into the prompt, with streaming enabled so responses feel instant. Data quality issues are found by deterministic code first (outlier detection, gap analysis), then passed to the model for plain-English explanation and prioritisation — the model explains, the code finds. Main constraint is context window: 500 buildings × 12 months of raw rows is too large, so context is summarised to annual aggregates per building with full monthly detail only fetched on demand for a specific building the user is asking about.', status: 'planned' },
];

