// Small ? icon that shows a tooltip on hover — for contextual field help
function TooltipIcon({ text, size = 14 }) {
  const [visible, setVisible] = useState(false);
  const [pos, setPos] = useState({ top: 0, left: 0 });
  const iconRef = useRef(null);

  const show = () => {
    if (!iconRef.current) return;
    const rect = iconRef.current.getBoundingClientRect();
    setPos({ top: rect.bottom + 6, left: Math.min(rect.left, window.innerWidth - 280) });
    setVisible(true);
  };

  return (
    <>
      <span
        ref={iconRef}
        onMouseEnter={show}
        onMouseLeave={() => setVisible(false)}
        style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
          width: size + 4, height: size + 4, borderRadius: '50%', background: T.paper,
          border: '1px solid ' + T.border, color: T.warmGrey, cursor: 'help',
          fontFamily: T.mono, fontSize: size - 3, fontWeight: 700, flexShrink: 0,
          userSelect: 'none', lineHeight: 1,
        }}
      >?</span>
      {visible && (
        <div style={{
          position: 'fixed', top: pos.top, left: pos.left,
          zIndex: 9999, maxWidth: 280, background: T.ink, color: '#fff',
          fontFamily: T.body, fontSize: 12, lineHeight: 1.55,
          padding: '8px 12px', borderRadius: 6,
          boxShadow: '0 4px 16px rgba(0,0,0,0.18)',
          pointerEvents: 'none',
        }}>
          {text}
        </div>
      )}
    </>
  );
}

function CsvFallbackModal() {
  const [data, setData] = useState(null);
  const [copied, setCopied] = useState(false);
  useEffect(() => __subscribeCsv((d) => { setData(d); setCopied(false); }), []);
  if (!data) return null;
  const onCopy = () => {
    const ta = document.createElement('textarea');
    ta.value = data.text; ta.style.cssText = 'position:fixed;opacity:0';
    document.body.appendChild(ta); ta.select();
    try { document.execCommand('copy'); setCopied(true); setTimeout(() => setCopied(false), 1500); } catch {}
    document.body.removeChild(ta);
    if (navigator.clipboard?.writeText) navigator.clipboard.writeText(data.text).catch(()=>{});
  };
  return (
    <Modal open={!!data} onClose={() => setData(null)} title={'CSV ready — ' + data.name} width={760}>
      <p style={{ fontFamily: T.body, fontSize: 13, color: T.warmGrey, lineHeight: 1.5, margin: '0 0 14px' }}>
        If a download didn't start, copy the text below and paste it into Excel, Google Sheets, or save it as <code style={{ fontFamily: T.mono, background: T.paper, padding: '1px 5px', borderRadius: 3 }}>{data.name}</code>.
      </p>
      <textarea readOnly value={data.text} onFocus={e => e.target.select()}
        style={{ width: '100%', height: 220, padding: 10, border: '1px solid ' + T.border, borderRadius: 6, fontFamily: T.mono, fontSize: 11, color: T.ink, boxSizing: 'border-box', resize: 'vertical' }}
      />
      <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', marginTop: 14 }}>
        <Button variant="secondary" onClick={() => setData(null)}>Close</Button>
        <Button onClick={onCopy} icon={copied ? Check : ClipboardPaste}>{copied ? 'Copied' : 'Copy CSV'}</Button>
      </div>
    </Modal>
  );
}


// =================================================================
// Overview Tab
