// ── Bill inference helpers ───────────────────────────────────────────────────
function inferMissingBills(buildings, energyRows, existingBills) {
  const bidsWithUserBills = new Set(existingBills.filter(b => !b.inferred).map(b => b.buildingId));
  const bldgMap = Object.fromEntries(buildings.map(b => [b.id, b]));
  const _uid = () => Math.random().toString(36).slice(2, 10);
  const inferred = [];
  energyRows.forEach(r => {
    if (!r.buildingId || !r.fuel || !r.year || !r.month) return;
    if (bidsWithUserBills.has(r.buildingId)) return;
    const bldg = bldgMap[r.buildingId];
    if (!bldg) return;
    const tariff = TARIFF_DATA[bldg.country]?.[r.fuel];
    if (!tariff) return;
    const kwh = parseFloat(r.kwh);
    if (!kwh || kwh <= 0) return;
    inferred.push({ id: _uid(), buildingId: r.buildingId, fuel: r.fuel, currency: tariff.cur, year: r.year, month: r.month, cost: parseFloat((kwh * tariff.rate).toFixed(2)), inferred: true });
  });
  return inferred;
}

function buildingsWithoutUserBills(buildings, energy, bills) {
  const bidsWithUserBills = new Set(bills.filter(b => !b.inferred).map(b => b.buildingId));
  const bidsWithEnergy = new Set(energy.map(r => r.buildingId).filter(Boolean));
  return new Set([...bidsWithEnergy].filter(id => !bidsWithUserBills.has(id)));
}

function OverviewTab({ buildings, energy, onNavigate, setBuildings, setEnergy, setBills, setFuels, setEfs, setRetrofits, setAssignments, push, onSampleLoad }) {
  const sampleDataLoaded = buildings.length > 0 && buildings[0]?.id === 'xaji0y6d';
  const [confirmClear, setConfirmClear] = useState(null); // null | 'energy' | 'portfolio' | 'all'

  const CLEAR_ACTIONS = {
    energy:    { label: 'Clear energy data',      desc: `Delete all ${energy.length.toLocaleString()} energy records. Buildings and emission factors are kept.`,                               action: () => { setEnergy([]);    push('Energy data cleared', 'success'); } },
    portfolio: { label: 'Clear portfolio',         desc: `Delete all ${buildings.length} buildings and their energy data.`,                                                                   action: () => { setBuildings([]); setEnergy([]); setBills([]); setAssignments([]); push('Portfolio and energy data cleared', 'success'); } },
    retrofits: { label: 'Clear retrofits',         desc: 'Delete all retrofit measures and building assignments.',                                                                             action: () => { setRetrofits([]); setAssignments([]); push('Retrofits cleared', 'success'); } },
    all:       { label: 'Reset everything',        desc: 'Delete all buildings, energy data, retrofits, and custom emission factor settings. Fuel list resets to defaults.',                  action: () => { setBuildings([]); setEnergy([]); setRetrofits([]); setAssignments([]); setEfs({}); setFuels(DEFAULT_FUELS); push('All data reset to defaults', 'success'); } },
  };

  const loadBuiltInSampleData = async () => {
    if (sampleDataLoaded) return;
    try {
      push('Loading 500-building dataset…', 'info');
      const _uid = () => Math.random().toString(36).slice(2, 10);
      const pResult = await new Promise(res =>
        Papa.parse(SAMPLE_PORTFOLIO_CSV, { header: true, skipEmptyLines: true, complete: res })
      );
      const buildingMap = {};
      pResult.data.forEach(r => {
        const id = r.building_id;
        if (!id) return;
        if (!buildingMap[id]) {
          buildingMap[id] = {
            id, name: r.building_name || id, address: r.address || '',
            country: r.country_code || '', gia: parseFloat(r.gia_m2) || 0,
            alpha: isNaN(parseFloat(r.alpha)) ? 0.5 : parseFloat(r.alpha),
            epc: r.epc_rating || '', assetClasses: [],
            heatingSystem:      r.heating_system || '',            heatingSystem:      r.heating_system || '',
            glazingType:        r.glazing_type || '',
            lightingType:       r.lighting_type || '',
            hasBMS:             r.has_bms === 'true',
            hasSolarPV:         r.has_solar_pv === 'true',
            solarPvM2:          parseFloat(r.solar_pv_m2) || 0,
            availableRoofM2:    r.available_roof_m2 !== undefined && r.available_roof_m2 !== '' ? parseFloat(r.available_roof_m2) : null,
            hasDHWHeatPump:     r.has_dhw_heat_pump  === 'true',
            hasRoofInsulation:  r.has_roof_insulation === 'true',
            hasWallInsulation:  r.has_wall_insulation === 'true',
            hasAirSealing:      r.has_air_sealing === 'true',
          };
        }
        buildingMap[id].assetClasses.push({ code: r.asset_class_code, pct: parseInt(r.asset_class_pct) || 100 });
      });
      const newBuildings = Object.values(buildingMap);
      const newEnergy = [];
      const newBills = [];
      SAMPLE_ENERGY_COMPACT.forEach(([buildingId, fuel, kwhArr, occArr]) => {
        const country = buildingMap[buildingId]?.country;
        const tariff = country ? TARIFF_DATA[country]?.[fuel] : null;
        // Ensure portfolio flag matches energy data: any building with renewables kWh gets hasSolarPV=true
        if (fuel === 'renewables' && buildingMap[buildingId] && !buildingMap[buildingId].hasSolarPV) {
          buildingMap[buildingId].hasSolarPV = true;
        }
        kwhArr.forEach((kwh, mi) => {
          if (kwh == null) return;
          newEnergy.push({ id: _uid(), buildingId, year: 2024, month: mi + 1, fuel, kwh, occupancy: occArr[mi] ?? '' });
          if (tariff && kwh > 0) {
            newBills.push({ id: _uid(), buildingId, fuel, currency: tariff.cur, year: 2024, month: mi + 1, cost: parseFloat((kwh * tariff.rate).toFixed(2)), inferred: false });
          }
        });
      });
      await setBuildings(newBuildings);
      await setEnergy(newEnergy);
      await setBills(newBills);
      push('Loaded ' + newBuildings.length + ' buildings, ' + newEnergy.length.toLocaleString() + ' energy readings and ' + newBills.length.toLocaleString() + ' utility bills', 'success');
      onSampleLoad?.();
    } catch (e) {
      push('Failed to load sample data: ' + e.message, 'error');
    }
  };;

;

  return (
    <div style={{ padding: '32px 48px', maxWidth: 1100, margin: '0 auto' }}>
      <PageHeader
        title="Overview"
        description="Calculate operational carbon, forecast trajectories to 2050, and benchmark every building in your portfolio against the CRREM 1.5°C decarbonisation pathways."
      />

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 20, marginBottom: 56 }}>
        <StatCard label="Buildings" value={buildings.length.toString()} sublabel={buildings.length === 0 ? 'None added yet' : 'In portfolio'} accent={buildings.length > 0 ? T.forest : T.warmGreyLight} />
        <StatCard label="Energy records" value={energy.length.toString()} sublabel={energy.length === 0 ? 'None added yet' : 'Monthly readings'} accent={energy.length > 0 ? T.forest : T.warmGreyLight} />
        <StatCard label="Countries" value={CRREM_DATA.countries.length.toString()} sublabel="CRREM-supported" />
        <StatCard label="Asset classes" value={CRREM_DATA.asset_classes.length.toString()} sublabel="Standard taxonomy" />
      </div>

      <SectionHeading num="01">Get started</SectionHeading>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 20, marginBottom: 56 }}>
        <ActionCard num="01" title="Add your portfolio" desc="Upload a CSV of buildings, or add them one at a time. Each building needs a country, GIA, and asset class split." action={() => onNavigate('portfolio')} actionLabel="Open Portfolio" />
        <ActionCard num="02" title="Add energy data" desc="Paste monthly energy bills directly from Excel into a spreadsheet grid, or upload as CSV. Configure non-electricity emission factors." action={() => onNavigate('energy')} actionLabel="Open Energy data" />
        <ActionCard num="03" title="Load sample data"
          desc={sampleDataLoaded
            ? "Sample data already loaded — clear from Portfolio and Energy tabs first."
            : "Instantly load a 500-building sample portfolio with a full year of energy data and inferred utility bills across 12 countries."}
          action={sampleDataLoaded ? null : loadBuiltInSampleData}
          actionLabel={sampleDataLoaded ? null : "Load 500-building dataset"}
        />
      </div>

      <SectionHeading num="02">Reference data</SectionHeading>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 32, marginBottom: 56, alignItems: 'stretch' }}>
        <ReferencePanel icon={Globe2} title="Supported countries" count={CRREM_DATA.countries.length} items={CRREM_DATA.countries.map(c => c.name)} initialShow={11} />
        <ReferencePanel icon={Layers} title="Asset classes" count={CRREM_DATA.asset_classes.length} items={CRREM_DATA.asset_classes.map(c => c.name)} initialShow={20} />
      </div>

      <SectionHeading num="03">Build progress</SectionHeading>
      <div style={{ marginBottom: 56 }}>
        {STAGES.map(s => (
          <div key={s.num} style={{
            display: 'grid', gridTemplateColumns: '32px 180px 1fr 110px',
            alignItems: 'center', padding: '14px 18px', gap: 12,
            background: '#fff', border: '1px solid ' + T.border,
            borderRadius: '6px', marginBottom: 6,
          }}>
            <div style={{ fontFamily: T.mono, fontSize: 11, color: T.warmGreyLight }}>
              {String(s.num).padStart(2, '0')}
            </div>
            <div style={{ fontFamily: T.body, fontSize: 14, color: T.ink, fontWeight: 500 }}>{s.label}</div>
            <div style={{ fontFamily: T.body, fontSize: 13, color: T.warmGrey }}>{s.desc}</div>
            <StatusBadge status={s.status} />
          </div>
        ))}
      </div>

      <div style={{ paddingTop: 24, borderTop: '1px solid ' + T.border, fontFamily: T.body, fontSize: 12, color: T.warmGreyLight, lineHeight: 1.6 }}>
        Pathway and grid emission factor data from the Carbon Risk Real Estate Monitor (CRREM), V2.04 (28 August 2025). www.crrem.org
      </div>
    </div>
  );
}

function StatCard({ label, value, sublabel, accent, delta, deltaText, deltaGood, tooltip }) {
  // delta: number = % change vs BAU (negative = improvement for carbon/energy tiles)
  // deltaText: pre-formatted string for non-% deltas (e.g. stranding years)
  // deltaGood: bool override — true=green, false=red (for deltaText where sign doesn't imply direction)
  const hasDelta = (delta != null && isFinite(delta)) || deltaText != null;
  const isGood = deltaText != null ? !!deltaGood : (delta != null && delta < 0);
  const deltaColor  = isGood ? '#16a34a' : '#dc2626';
  const deltaBg     = isGood ? '#f0fdf4' : '#fef2f2';
  const deltaBorder = isGood ? '#bbf7d0' : '#fecaca';
  const badge = deltaText != null
    ? deltaText
    : delta != null ? (delta < 0 ? '▼ ' : '▲ ') + Math.abs(delta).toFixed(1) + '% vs BAU' : null;
  return (
    <div style={{
      padding: '14px 16px', background: '#fff',
      border: '1px solid ' + T.border, borderRadius: '8px',
      minWidth: 0,
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 6 }}>
        <div title={label} style={{
          fontFamily: T.body, fontSize: 10, fontWeight: 500,
          textTransform: 'uppercase', letterSpacing: '0.06em',
          color: T.warmGrey,
          whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
        }}>{label}</div>
        {tooltip && <TooltipIcon text={tooltip} size={12} />}
      </div>
      <div title={typeof value === 'string' || typeof value === 'number' ? String(value) : undefined} style={{
        fontFamily: T.body, fontSize: 22, lineHeight: 1.2,
        color: accent || T.ink, fontWeight: 600, marginBottom: 3,
        whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
      }}>{value}</div>
      <div style={{ fontFamily: T.body, fontSize: 11, color: T.warmGrey, lineHeight: 1.35 }}>{sublabel}</div>
      {hasDelta && badge && (
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 3, marginTop: 6,
          padding: '2px 7px', borderRadius: 20,
          background: deltaBg, border: '1px solid ' + deltaBorder,
          fontFamily: T.mono, fontSize: 11, fontWeight: 600, color: deltaColor,
          whiteSpace: 'nowrap',
        }}>
          {badge}
        </div>
      )}
    </div>
  );
}

function StatusBadge({ status }) {
  const styles = {
    done:    { bg: '#dcfce7', fg: '#166534',     label: 'Complete'    },
    partial: { bg: '#fef9c3', fg: '#854d0e',     label: 'Partial'     },
    next:    { bg: '#fef3c7', fg: '#92400e',     label: 'In progress' },
    pending: { bg: T.paper,   fg: T.warmGreyLight, label: 'Queued'    },
    planned: { bg: '#eff6ff', fg: '#1e40af',     label: 'Planned'     },
  }[status] || { bg: T.paper, fg: T.warmGreyLight, label: status };
  return (
    <div style={{
      fontFamily: T.body, fontSize: 11, fontWeight: 500,
      padding: '4px 10px', background: styles.bg, color: styles.fg,
      borderRadius: '20px', textAlign: 'center', justifySelf: 'end', whiteSpace: 'nowrap',
    }}>{styles.label}</div>
  );
}

function ReferencePanel({ icon: Icon, title, count, items, initialShow = 8 }) {
  const [expanded, setExpanded] = useState(false);
  const display = expanded ? items : items.slice(0, initialShow);
  return (
    <div style={{ padding: '20px 24px', background: '#fff', border: '1px solid ' + T.border, borderRadius: '8px' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 16 }}>
        <Icon size={15} color={T.forest} strokeWidth={1.8} />
        <span style={{ fontFamily: T.body, fontSize: 13, fontWeight: 600, color: T.ink }}>{title}</span>
        <span style={{ fontFamily: T.body, fontSize: 11, color: T.warmGrey, marginLeft: 'auto', background: T.paper, padding: '2px 8px', borderRadius: '20px' }}>{count}</span>
      </div>
      <div style={{ fontFamily: T.body, fontSize: 14, color: T.inkSoft, lineHeight: 1.7 }}>
        {display.map((item, i) => (
          <div key={i} style={{ borderTop: i === 0 ? 'none' : '1px solid ' + T.borderSoft, padding: '8px 0' }}>{item}</div>
        ))}
        {!expanded && items.length > initialShow && (
          <button onClick={() => setExpanded(true)} style={{
            fontFamily: T.mono, fontSize: 11, letterSpacing: '0.1em', textTransform: 'uppercase',
            color: T.forest, background: 'none', border: 'none', cursor: 'pointer', padding: '12px 0 0',
          }}>+ Show all {items.length}</button>
        )}
      </div>
    </div>
  );
}

function ActionCard({ num, title, desc, action, actionLabel, secondaryAction, secondaryLabel }) {
  return (
    <div style={{ padding: '20px 24px', background: '#fff', border: '1px solid ' + T.border, borderRadius: '8px', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ fontFamily: T.body, fontSize: 15, fontWeight: 600, color: T.ink, margin: '0 0 8px' }}>{title}</h3>
      <p style={{ fontFamily: T.body, fontSize: 13, color: T.warmGrey, lineHeight: 1.6, margin: '0 0 20px', flexGrow: 1 }}>{desc}</p>
      <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
        {action && <Button onClick={action} icon={ChevronRight} variant="success" style={{ alignSelf: 'flex-start' }}>{actionLabel}</Button>}
        {secondaryAction && <Button onClick={secondaryAction} variant="secondary" style={{ alignSelf: 'flex-start' }}>{secondaryLabel}</Button>}
      </div>
    </div>
  );
}

