  ES:[40.4,-3.7], IT:[41.9,12.6], PL:[52.0,20.0], SE:[62.0,15.0], NO:[65.0,14.0],
  DK:[56.0,10.0], FI:[64.0,26.0], AT:[47.5,13.5], CH:[47.0,8.2], IE:[53.2,-8.2],
  PT:[39.6,-8.0], CZ:[49.8,15.5], HU:[47.2,19.5], RO:[45.9,25.0], SK:[48.7,19.7],
  LU:[49.8,6.1], SI:[46.1,14.8], LT:[55.9,23.9], LV:[57.0,25.0], EE:[58.7,25.0],
  US:[39.5,-98.4], CA:[56.1,-106.3], AU:[-25.3,133.8], NZ:[-41.3,174.8],
  JP:[36.2,138.3], KR:[37.0,127.8], SG:[1.4,103.8], HK:[22.3,114.2],
