// CoordPicker — uses Anthropic API to look up coordinates from address/name.
// No external mapping services needed; works inside the artifact sandbox.
function CoordPicker({ address, country, lat, lon, onChange }) {
  const [status, setStatus] = useState('idle'); // idle | loading | done | error
  const [errorMsg, setErrorMsg] = useState('');

  const hasCoords = lat !== '' && lat != null && lon !== '' && lon != null;

  const lookup = async () => {
    const query = [address, country ? countryName(country) : ''].filter(Boolean).join(', ');
    if (!query.trim()) return;
    setStatus('loading');
    setErrorMsg('');
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 60,
          system: 'Return ONLY a JSON object {"lat": number, "lon": number} (5 decimal places) for the given address. No markdown, no commentary.',
          messages: [{ role: 'user', content: 'Coordinates for: ' + query }],
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error((data?.error?.message || 'HTTP ' + res.status));
      const text = (data.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
      const parsed = JSON.parse(text.replace(/^```[a-z]*\n?/i, '').replace(/\n?```$/, ''));
      if (typeof parsed.lat !== 'number' || typeof parsed.lon !== 'number') throw new Error('Unexpected response format');
      onChange({ lat: parsed.lat.toFixed(6), lon: parsed.lon.toFixed(6) });
      setStatus('done');
    } catch (e) {
      setErrorMsg(e.message || 'Unknown error');
      setStatus('error');
    }
  };

  const canLookup = !!(address || country);

  return (
    <div style={{ marginTop: 8, display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
      {canLookup && (
        <button
          type="button"
          onClick={lookup}
          disabled={status === 'loading'}
          style={{
            fontFamily: T.body, fontSize: 12,
            color: status === 'loading' ? T.warmGrey : T.forest,
            background: 'none',
            border: '1px dashed ' + (status === 'loading' ? T.border : T.forestSoft),
            borderRadius: 6, padding: '6px 12px',
            cursor: status === 'loading' ? 'default' : 'pointer',
            display: 'inline-flex', alignItems: 'center', gap: 6,
          }}
        >
          <MapPin size={13} strokeWidth={2} />
          {status === 'loading'
            ? 'Looking up coordinates…'
            : hasCoords
            ? 'Re-lookup coordinates'
            : 'Look up coordinates from address'}
        </button>
      )}
      {status === 'done' && (
        <span style={{ fontFamily: T.body, fontSize: 12, color: T.forest, display: 'flex', alignItems: 'center', gap: 4 }}>
          <Check size={13} strokeWidth={2.5} /> Coordinates set
        </span>
      )}
      {status === 'error' && (
        <span style={{ fontFamily: T.body, fontSize: 12, color: T.rose }}>
          Could not find location: {errorMsg}. Enter coordinates manually above.
        </span>
      )}
      {!canLookup && !hasCoords && (
        <span style={{ fontFamily: T.body, fontSize: 12, color: T.warmGrey }}>
          Enter an address or country above to enable coordinate lookup.
        </span>
      )}
    </div>
  );
}

// =================================================================
// Building Form (modal)
// =================================================================
function BuildingForm({ open, onClose, onSave, building, allBuildings }) {
  const emptyDraft = () => ({
    id: uid(), name: '', address: '', country: '', gia: '', alpha: 0.5, epc: '',
    latitude: '', longitude: '',
    assetClasses: [{ code: '', pct: 100 }],
    heatingSystem: '', glazingType: '', lightingType: '', hasBMS: false, hasSolarPV: false, hasEfficientHVAC: false, hasDHWHeatPump: false, hasRoofInsulation: false, hasWallInsulation: false, hasAirSealing: false, availableRoofM2: '',
  });
  const [draft, setDraft] = useState(() => building || emptyDraft());
  const [submitted, setSubmitted] = useState(false);
  const [confirmDiscard, setConfirmDiscard] = useState(false);
  // Track whether any field has been touched since the form opened
  const initialDraftRef = useRef(null);

  useEffect(() => {
    if (open) {
      const initial = building || emptyDraft();
      setDraft(initial);
      initialDraftRef.current = JSON.stringify(initial);
      setSubmitted(false);
      setConfirmDiscard(false);
    }
  }, [open, building]);

  const isDirty = JSON.stringify(draft) !== initialDraftRef.current;

  const handleClose = () => {
    if (isDirty) { setConfirmDiscard(true); return; }
    onClose();
  };

  const validation = useMemo(() => validateBuilding(draft, allBuildings), [draft, allBuildings]);

  const update = (patch) => setDraft(d => ({ ...d, ...patch }));
  const addAssetClass = () => update({ assetClasses: [...draft.assetClasses, { code: '', pct: 0 }] });
  const removeAssetClass = (i) => update({ assetClasses: draft.assetClasses.filter((_, j) => j !== i) });
  const updateAssetClass = (i, patch) => update({
    assetClasses: draft.assetClasses.map((ac, j) => j === i ? { ...ac, ...patch } : ac),
  });

  const handleSave = () => {
    setSubmitted(true);
    if (validation.errors.length === 0) {
      const lat = draft.latitude !== '' && draft.latitude != null ? parseFloat(draft.latitude) : null;
      const lon = draft.longitude !== '' && draft.longitude != null ? parseFloat(draft.longitude) : null;
      onSave({ ...draft, gia: parseFloat(draft.gia), alpha: parseFloat(draft.alpha), latitude: lat, longitude: lon });
      onClose();
    }
  };

  const acSum = draft.assetClasses.reduce((s, x) => s + (parseFloat(x.pct) || 0), 0);

  return (
    <>
    <Modal open={open} onClose={handleClose} title={building?.name ? 'Edit building' : 'Add building'} width={760} disableBackdropClick>
      {submitted && <ValidationSummary errors={validation.errors} warnings={validation.warnings} />}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 16 }}>
        <Input label="Building name" value={draft.name} onChange={v => update({ name: v })} placeholder="e.g. Vine Court" />
        <Input label="Address" value={draft.address} onChange={v => update({ address: v })} placeholder="123 Example St, City" />
      </div>

      <div style={{ marginBottom: 16 }}>
        <label style={{ fontFamily: T.mono, fontSize: 10, letterSpacing: '0.12em', textTransform: 'uppercase', color: T.warmGrey, display: 'block', marginBottom: 8 }}>
          Coordinates (for map display)
        </label>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          <Input label="Latitude" value={draft.latitude ?? ''} onChange={v => update({ latitude: v })}
            type="number" step="0.000001" placeholder="e.g. 51.5074" />
          <Input label="Longitude" value={draft.longitude ?? ''} onChange={v => update({ longitude: v })}
            type="number" step="0.000001" placeholder="e.g. -0.1278" />
        </div>
        <CoordPicker
          address={draft.address}
          country={draft.country}
          lat={draft.latitude}
          lon={draft.longitude}
          onChange={({ lat, lon }) => update({ latitude: lat, longitude: lon })}
        />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr', gap: 16, marginBottom: 16 }}>
        <Select
          label="Country"
          value={draft.country}
          onChange={v => update({ country: v })}
          options={CRREM_DATA.countries.map(c => ({ value: c.code, label: c.name + ' (' + c.code + ')' }))}
        />
        <Input label="GIA" value={draft.gia} onChange={v => update({ gia: v })} type="number" suffix="m²" placeholder="2500"
          tooltip="Gross Internal Area — the total floor area inside the external walls, measured in m². All carbon and energy intensity figures are divided by GIA to produce kgCO₂e/m²/yr and kWh/m²/yr." />
        <Select
          label="EPC rating"
          value={draft.epc}
          onChange={v => update({ epc: v })}
          options={EPC_RATINGS.map(r => ({ value: r, label: r }))}
          placeholder="Optional"
          tooltip="Energy Performance Certificate rating (A–G). Informational only — not used in CRREM calculations, but useful for filtering and reporting."
        />
      </div>

      <div style={{ marginBottom: 16 }}>
        <Input
          label="α (alpha) — fixed energy fraction (0–1)"
          value={draft.alpha} onChange={v => update({ alpha: v })}
          type="number" step="0.05" min="0" max="1"
          hint="Controls how occupancy data normalises energy consumption when comparing buildings. α = 1 means all energy is treated as fixed (base-building HVAC, lifts, server rooms, common-area lighting) — occupancy has no effect. α = 0 means all energy scales proportionally with occupancy. Values in between split consumption between fixed and variable. Use 0.5 as a safe default; refine with submetering data where available."
        />
      </div>

      <div style={{ marginBottom: 24 }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
            <label style={{ fontFamily: T.mono, fontSize: 10, letterSpacing: '0.12em', textTransform: 'uppercase', color: T.warmGrey }}>
              Asset class split
            </label>
            <TooltipIcon text="The CRREM property type(s) for this building. Each asset class has its own decarbonisation pathway. For mixed-use buildings add multiple rows — percentages must sum to 100%. The pathway shown is a GIA-weighted blend." />
          </div>
          <span style={{ fontFamily: T.mono, fontSize: 11, color: Math.abs(acSum - 100) < 0.1 ? T.forest : T.rose, fontWeight: 600 }}>
            Total: {acSum.toFixed(1)}%
          </span>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {draft.assetClasses.map((ac, i) => (
            <div key={i} style={{ display: 'grid', gridTemplateColumns: '1fr 120px 40px', gap: 8, alignItems: 'center' }}>
              <Select
                value={ac.code}
                onChange={v => updateAssetClass(i, { code: v })}
                options={CRREM_DATA.asset_classes.map(c => ({ value: c.code, label: c.name }))}
              />
              <Input value={ac.pct} onChange={v => updateAssetClass(i, { pct: v })} type="number" suffix="%" />
              {draft.assetClasses.length > 1 && (
                <button onClick={() => removeAssetClass(i)} style={{
                  background: 'transparent', border: '1px solid ' + T.border, padding: 9,
                  cursor: 'pointer', color: T.rose, display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  <Trash2 size={14} strokeWidth={1.7} />
                </button>
              )}
            </div>
          ))}
        </div>
        <button onClick={addAssetClass} style={{
          background: T.paper, border: '1px dashed ' + T.border, padding: '10px 14px', borderRadius: '6px',
          fontFamily: T.body, fontSize: 13, color: T.forest, cursor: 'pointer', marginTop: 8, width: '100%',
          display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
        }}>
          <Plus size={14} strokeWidth={1.8} /> Add asset class
        </button>
      </div>

      {/* ── Retrofit data (Tier 2) ─────────────────────────────────────────── */}
      <div style={{ borderTop: '1px solid ' + T.border, paddingTop: 20, marginBottom: 20 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 14 }}>
          <Wrench size={14} strokeWidth={1.8} color={T.warmGrey} />
          <span style={{ fontFamily: T.mono, fontSize: 10, letterSpacing: '0.12em', textTransform: 'uppercase', color: T.warmGrey }}>
            Retrofit data <span style={{ fontFamily: T.body, textTransform: 'none', letterSpacing: 0, color: T.warmGreyLight }}>(optional — improves retrofit modelling accuracy)</span>
          </span>
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 16 }}>
          <Select label="Heating system" value={draft.heatingSystem || ''}
            onChange={v => update({ heatingSystem: v })}
            options={HEATING_SYSTEM_OPTIONS} placeholder="Unknown"
            tooltip="The primary heating fuel or technology. Used to determine which fuel-switch measures apply. Buildings on electric boilers record all heating as electricity — their heating load cannot be isolated for fuel-switch modelling." />
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 16 }}>
          <Select label="Glazing type" value={draft.glazingType || ''}
            onChange={v => update({ glazingType: v })}
            options={GLAZING_TYPE_OPTIONS} placeholder="Unknown"
            tooltip="Type of window glazing installed. Affects the estimated savings from a high-performance glazing upgrade measure." />
          <Select label="Lighting type" value={draft.lightingType || ''}
            onChange={v => update({ lightingType: v })}
            options={LIGHTING_TYPE_OPTIONS} placeholder="Unknown"
            tooltip="Predominant lighting technology. Scales the electricity saving from an LED upgrade: incandescent → LED saves ~20%, fluorescent → LED ~10%, mixed ~15%. Buildings already on LED will show an incompatibility warning." />
        </div>
        <div style={{ display: 'flex', gap: 24, flexWrap: 'wrap' }}>
          {[
            { key: 'hasBMS',             label: 'Has BMS / building automation system' },
            { key: 'hasSolarPV',         label: 'Has existing solar PV' },
            { key: 'hasEfficientHVAC',   label: 'Has efficient HVAC system' },
            { key: 'hasDHWHeatPump',     label: 'Has DHW heat pump' },
            { key: 'hasRoofInsulation',  label: 'Has roof / loft insulation' },
            { key: 'hasWallInsulation',  label: 'Has wall insulation (cavity or external)' },
            { key: 'hasAirSealing',      label: 'Has air sealing / draught-proofing' },
          ].map(({ key, label }) => (
            <label key={key} style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontFamily: T.body, fontSize: 13, color: T.inkSoft }}>
              <input type="checkbox" checked={!!draft[key]} onChange={e => update({ [key]: e.target.checked })}
                style={{ width: 15, height: 15, accentColor: T.forest, cursor: 'pointer' }} />
              {label}
            </label>
          ))}
        </div>
        <div style={{ marginTop: 16 }}>
          <Input
            label="Available roof area for solar PV (m²)"
            value={draft.availableRoofM2 ?? ''}
            onChange={v => update({ availableRoofM2: v })}
            type="number"
            placeholder={draft.gia && draft.assetClasses?.length ? ('e.g. ' + (defaultSolarRoofM2(draft) ?? '')) : 'e.g. 250'}
          />
          <div style={{ fontFamily: T.body, fontSize: 11, color: T.warmGrey, marginTop: 4, lineHeight: 1.4 }}>
            Roof area available for new or additional PV panels — excluding existing panels, plant, and access zones.
            {(!draft.availableRoofM2 || draft.availableRoofM2 === '') && (() => {
              const def = defaultSolarRoofM2(draft);
              return def ? <span> If left blank, a default of <strong>{def.toLocaleString()} m²</strong> will be used when modelling solar PV.</span> : null;
            })()}
          </div>
        </div>
      </div>

      <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', borderTop: '1px solid ' + T.border, paddingTop: 20 }}>
        <Button variant="secondary" onClick={handleClose}>Cancel</Button>
        <Button onClick={handleSave} icon={Save}>{building?.name ? 'Save changes' : 'Add building'}</Button>
      </div>
    </Modal>
    <ConfirmDialog
      open={confirmDiscard}
      title="Discard changes?"
      message="You have unsaved changes to this building. Leave without saving?"
      confirmLabel="Discard changes"
      confirmVariant="danger"
      onConfirm={() => { setConfirmDiscard(false); onClose(); }}
      onCancel={() => setConfirmDiscard(false)}
    />
  </>
  );
}

// =================================================================
// Portfolio Tab
// =================================================================
const PORTFOLIO_TEMPLATE_XLSX_B64 = "";

function PortfolioTab({ buildings, setBuildings, energy, setEnergy, setBills, setAssignments, push }) {
  const [editing, setEditing] = useState(null);
  const [open, setOpen] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(null);
  const [confirmClear, setConfirmClear] = useState(false);
  const [issueFilter, setIssueFilter] = useState('all'); // 'all' | 'errors' | 'warnings'
  const [portfolioSearch, setPortfolioSearch] = useState('');
  const fileInputRef = useRef(null);

  const handleAdd = () => { setEditing(null); setOpen(true); };
  const handleEdit = (b) => { setEditing(b); setOpen(true); };
  const handleSave = (b) => {
    const idx = buildings.findIndex(x => x.id === b.id);
    if (idx >= 0) {
      const next = [...buildings]; next[idx] = b; setBuildings(next);
      push('Building updated', 'success');
    } else {
      setBuildings([...buildings, b]);
      push('Building added', 'success');
    }
  };
  const handleDelete = (b) => {
    setBuildings(buildings.filter(x => x.id !== b.id));
    push('Building deleted', 'success');
    setConfirmDelete(null);
  };

  // Build asset class options string for the template comment row
  const AC_OPTIONS = CRREM_DATA.asset_classes.map(a => a.name + ' (' + a.code + ')').join(' | ');
  const TEMPLATE_ROWS = [{
    building_id: '(instructions)', building_name: 'Required — unique name',
    address: 'Optional', country_code: 'e.g. UK (see CRREM country list)',
    gia_m2: 'Gross Internal Area in m²',
    asset_class_name: 'Choose one: ' + AC_OPTIONS,
    asset_class_pct: '% of GIA for this asset class (rows with same building_id are summed; must total 100)',
    epc_rating: 'A+++/A++/A+/A/B/C/D/E/F/G or blank', alpha: '0–1 (fixed energy fraction; 0.5 if unsure)',
  }, {
    building_id: 'BLDG-001', building_name: 'Example Office', address: '1 High Street, London',
    country_code: 'UK', gia_m2: 2500,
    asset_class_name: 'Office (OFF)',
    asset_class_pct: 100, epc_rating: 'C', alpha: 0.5,
  }, {
    building_id: 'BLDG-002', building_name: 'Mixed-use Building', address: '5 Market Square, Manchester',
    country_code: 'UK', gia_m2: 4000,
    asset_class_name: 'Office (OFF)',
    asset_class_pct: 60, epc_rating: 'B', alpha: 0.5,
  }, {
    building_id: 'BLDG-002', building_name: 'Mixed-use Building', address: '5 Market Square, Manchester',
    country_code: 'UK', gia_m2: 4000,
    asset_class_name: 'Retail — High Street (RHS)',
    asset_class_pct: 40, epc_rating: 'B', alpha: 0.5,
  }];

  const downloadTemplate = () => {
    // Download pre-built xlsx with dropdowns (base64-encoded at module level)
    try {
      const binary = atob(PORTFOLIO_TEMPLATE_XLSX_B64);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const blob = new Blob([bytes], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url; a.download = 'portfolio_template.xlsx'; a.style.display = 'none';
      document.body.appendChild(a); a.click();
      setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 150);
      push('Template downloaded — open in Excel, fill in the Portfolio tab, then save as CSV to import', 'success');
    } catch {
      push('Template download failed', 'error');
    }
  };

  const [copied, setCopied] = useState(false);
  const exportBuildings = () => {
    const rows = [];
    buildings.forEach(b => {
      (b.assetClasses || [{ code: '', pct: 100 }]).forEach(ac => {
        rows.push({
          building_id:          b.id,
          building_name:        b.name,
          address:              b.address || '',
          country_code:         b.country,
          gia_m2:               b.gia,
          asset_class_code:     ac.code,
          asset_class_pct:      ac.pct,
          epc_rating:           b.epc || '',
          alpha:                b.alpha,
          heating_system:       b.heatingSystem      || '',          heating_system:       b.heatingSystem      || '',
          glazing_type:         b.glazingType        || '',
          lighting_type:        b.lightingType       || '',
          has_bms:              b.hasBMS             ?? false,
          has_solar_pv:         b.hasSolarPV         ?? false,
          has_efficient_hvac:   b.hasEfficientHVAC   ?? false,
          has_dhw_heat_pump:    b.hasDHWHeatPump     ?? false,
          has_roof_insulation:  b.hasRoofInsulation  ?? false,
          has_wall_insulation:  b.hasWallInsulation  ?? false,
          has_air_sealing:      b.hasAirSealing      ?? false,
          solar_pv_m2:          b.solarPvM2          || 0,
          available_roof_m2:    b.availableRoofM2 != null && b.availableRoofM2 !== '' ? parseFloat(b.availableRoofM2) : '',
        });
      });
    });
    directDownload('portfolio_export.csv', rows);
    push('Portfolio exported', 'success');
  };


  const totalGIA = buildings.reduce((s, b) => s + (parseFloat(b.gia) || 0), 0);
  const countriesUsed = new Set(buildings.map(b => b.country)).size;

  // Build a set of building IDs that have any renewables energy rows
  const buildingsWithRenewables = useMemo(() =>
    new Set(energy.filter(r => r.fuel === 'renewables').map(r => r.buildingId)),
    [energy]
  );

  // Per-building validation (memoised) — includes solar PV ↔ renewables cross-checks
  const buildingValidations = useMemo(() =>
    buildings.map(b => {
      const v = validateBuilding(b, buildings);
      const hasRenewablesData = buildingsWithRenewables.has(b.id);
      if (b.hasSolarPV && !hasRenewablesData)
        v.warnings.push('has_solar_pv is set but no renewables energy data found — upload renewables kWh or the existing generation will not be reflected in calculations');
      if (!b.hasSolarPV && hasRenewablesData)
        v.warnings.push('Renewables energy data found but has_solar_pv is not set — check the Portfolio field to confirm this building has on-site generation');
      return { b, v };
    }),
    [buildings, buildingsWithRenewables]
  );
  const errBuildings = buildingValidations.filter(({ v }) => v.errors.length > 0);
  const warnBuildings = buildingValidations.filter(({ v }) => v.errors.length === 0 && v.warnings.length > 0);
  // Detect duplicate names (caught by validateBuilding as an error, but we surface a count too)
  const dupNames = useMemo(() => {
    const seen = {}; const dups = new Set();
    buildings.forEach(b => {
      const key = (b.name || '').trim().toLowerCase();
      if (key && seen[key]) dups.add(key);
      else seen[key] = true;
    });
    return dups;
  }, [buildings]);

  // Filtered list for the table
  const filteredBuildings = useMemo(() => {
    let list = buildings;
    if (issueFilter === 'errors') list = list.filter(b => buildingValidations.find(x => x.b.id === b.id)?.v.errors.length > 0);
    else if (issueFilter === 'warnings') list = list.filter(b => {
      const val = buildingValidations.find(x => x.b.id === b.id)?.v;
      return val && val.errors.length === 0 && val.warnings.length > 0;
    });
    if (portfolioSearch.trim()) {
      const q = portfolioSearch.trim().toLowerCase();
      list = list.filter(b =>
        (b.name || '').toLowerCase().includes(q) ||
        (b.address || '').toLowerCase().includes(q) ||
        (b.id || '').toLowerCase().includes(q) ||
        (b.country || '').toLowerCase().includes(q)
      );
    }
    return list;
  }, [buildings, buildingValidations, issueFilter, portfolioSearch]);

  return (
    <div style={{ padding: '32px 48px', maxWidth: 1300, margin: '0 auto' }}>
      <PageHeader
        title="Portfolio"
        description="Add buildings to the portfolio. Use the CSV upload for bulk imports, or add individually with the form. For mixed-use buildings, repeat the row with each asset class — percentages must sum to 100%."
        actions={<>
          <input ref={fileInputRef} type="file" accept=".csv" style={{ display: 'none' }} onChange={(e) => handleCsvUpload(e, buildings, setBuildings, push)} />
          <Button variant="secondary" size="sm" icon={Download} onClick={downloadTemplate}>Download Excel template</Button>
          <Button variant="secondary" size="sm" icon={Upload} onClick={() => fileInputRef.current?.click()}>Upload CSV</Button>
          {buildings.length > 0 && <Button variant="secondary" size="sm" icon={Download} onClick={exportBuildings}>Export portfolio</Button>}
          {buildings.length > 0 && <Button variant="danger" size="sm" icon={Trash2} onClick={() => setConfirmClear(true)}>Clear all</Button>}
          <Button size="sm" icon={Plus} onClick={handleAdd}>Add building</Button>
        </>}
      />

      <TabInfoAccordion title="About this section">
        <p style={{ margin: '0 0 8px' }}>Each building needs a <strong>country code</strong>, <strong>GIA in m²</strong>, and at least one <strong>asset class with a percentage</strong> — these three fields drive every CRREM calculation. Mixed-use buildings use multiple rows with the same <code style={{ fontFamily: T.mono, fontSize: '0.9em', background: T.paper, border: '1px solid ' + T.border, borderRadius: 3, padding: '1px 4px' }}>building_id</code>; asset class percentages must sum to 100%.</p>
        <p style={{ margin: '0 0 8px' }}><strong>α (alpha)</strong> controls how monthly occupancy data normalises energy consumption when comparing buildings — a higher value means more energy is treated as fixed (independent of how full the building is). Use <strong>0.5</strong> if unsure; the Occupancy section in Energy data must be populated for it to have any effect.</p>
        <p style={{ margin: '0 0 8px' }}>The optional retrofit fields (<code style={{ fontFamily: T.mono, fontSize: '0.9em', background: T.paper, border: '1px solid ' + T.border, borderRadius: 3, padding: '1px 4px' }}>heating_system</code>, <code style={{ fontFamily: T.mono, fontSize: '0.9em', background: T.paper, border: '1px solid ' + T.border, borderRadius: 3, padding: '1px 4px' }}>lighting_type</code>, <code style={{ fontFamily: T.mono, fontSize: '0.9em', background: T.paper, border: '1px solid ' + T.border, borderRadius: 3, padding: '1px 4px' }}>has_bms</code> etc.) improve retrofit modelling accuracy and unlock Smart select and incompatibility warnings in the Retrofits tab.</p>
        <p style={{ margin: 0, color: T.warmGrey }}>See the <strong>Guide</strong> tab → User guide for a full field reference and CSV template walkthrough.</p>
      </TabInfoAccordion>

      {buildings.length > 0 && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 20, marginBottom: 24 }}>
          <StatCard label="Buildings" value={buildings.length.toString()} sublabel="Properties" />
          <StatCard label="Total GIA" value={(totalGIA / 1000).toFixed(1) + 'k'} sublabel="m²" />
          <StatCard label="Countries" value={countriesUsed.toString()} sublabel="In portfolio" />
          <StatCard
            label="Issues"
            value={(errBuildings.length + warnBuildings.length).toString()}
            sublabel={errBuildings.length > 0 ? errBuildings.length + ' with errors' : warnBuildings.length > 0 ? 'Warnings only' : 'All clean'}
            accent={errBuildings.length > 0 ? T.rose : warnBuildings.length > 0 ? T.amber : T.forest}
          />
        </div>
      )}

      {buildings.length > 0 && (
        <div style={{ marginBottom: 12 }}>
          <input
            type="text"
            placeholder="Search buildings by name, address, ID or country…"
            value={portfolioSearch}
            onChange={e => setPortfolioSearch(e.target.value)}
            style={{
              width: '100%', boxSizing: 'border-box',
              fontFamily: T.body, fontSize: 13, color: T.ink,
              border: '1px solid ' + T.border, borderRadius: 8,
              padding: '8px 14px', outline: 'none', background: '#fff',
            }}
          />
        </div>
      )}

      {buildings.length > 0 && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16 }}>
          {[
            { key: 'all', label: 'All', count: buildings.length },
            { key: 'errors', label: 'Errors', count: errBuildings.length, color: T.rose, bg: '#fef2f2' },
            { key: 'warnings', label: 'Warnings', count: warnBuildings.length, color: T.amber, bg: '#fffbeb' },
          ].map(({ key, label, count, color, bg }) => {
            const active = issueFilter === key;
            return (
              <button key={key} onClick={() => setIssueFilter(key)} style={{
                display: 'flex', alignItems: 'center', gap: 6,
                padding: '6px 12px', borderRadius: '20px', cursor: 'pointer',
                fontFamily: T.body, fontSize: 13, fontWeight: active ? 600 : 400,
                background: active ? (bg || T.slate) : '#fff',
                color: active ? (color || '#fff') : T.warmGrey,
                border: '1px solid ' + (active ? (color || T.slate) : T.border),
                transition: 'all 0.12s',
              }}>
                {label}
                <span style={{
                  background: active ? (color || T.slate) : T.paper,
                  color: active ? '#fff' : T.warmGrey,
                  borderRadius: '20px', padding: '1px 7px', fontSize: 11, fontWeight: 600,
                }}>{count}</span>
              </button>
            );
          })}
          {issueFilter !== 'all' && (
            <span style={{ fontFamily: T.body, fontSize: 12, color: T.warmGrey, marginLeft: 4 }}>
              Showing {filteredBuildings.length} of {buildings.length} buildings
            </span>
          )}
        </div>
      )}

      {buildings.length === 0 ? (
        <EmptyState
          icon={Building2}
          title="No buildings yet"
          message="Start by uploading a CSV with your portfolio, or add buildings one at a time using the form."
          action={
            <div style={{ display: 'flex', gap: 10, justifyContent: 'center' }}>
              <Button icon={Plus} onClick={handleAdd}>Add building</Button>
              <Button variant="secondary" icon={Upload} onClick={() => fileInputRef.current?.click()}>Upload CSV</Button>
            </div>
          }
        />
      ) : filteredBuildings.length === 0 ? (
        <div style={{ background: '#fff', border: '1px solid ' + T.border, borderRadius: '8px', padding: '48px 32px', textAlign: 'center', fontFamily: T.body, fontSize: 14, color: T.warmGrey }}>
          No buildings match{portfolioSearch ? ' "' + portfolioSearch + '"' : ' this filter'}.
          {portfolioSearch && <button onClick={() => setPortfolioSearch('')} style={{ display: 'block', margin: '8px auto 0', fontFamily: T.body, fontSize: 13, color: T.forest, background: 'none', border: 'none', cursor: 'pointer', textDecoration: 'underline' }}>Clear search</button>}
        </div>
      ) : (
        <BuildingsTable buildings={filteredBuildings} allBuildings={buildings} buildingValidations={buildingValidations} onEdit={handleEdit} onDelete={(b) => setConfirmDelete(b)} />
      )}

      <BuildingForm open={open} onClose={() => setOpen(false)} onSave={handleSave} building={editing} allBuildings={buildings} />
      <ConfirmDialog
        open={!!confirmDelete}
        title="Delete building?"
        message={confirmDelete ? 'This will remove "' + confirmDelete.name + '" and all its energy data records. This cannot be undone.' : ''}
        onConfirm={() => handleDelete(confirmDelete)}
        onCancel={() => setConfirmDelete(null)}
        confirmLabel="Delete"
      />
      <ConfirmDialog
        open={confirmClear}
        title="Clear entire portfolio?"
        message={`This will permanently delete all ${buildings.length} building${buildings.length !== 1 ? 's' : ''} and all ${energy.length.toLocaleString()} energy records. This cannot be undone.`}
        onConfirm={() => { setBuildings([]); setEnergy([]); setBills([]); setAssignments([]); setConfirmClear(false); push('Portfolio and energy data cleared', 'success'); }}
        onCancel={() => setConfirmClear(false)}
        confirmLabel="Clear all"
      />
    </div>
  );
}

function BuildingsTable({ buildings, allBuildings, buildingValidations, onEdit, onDelete }) {
  return (
    <div style={{ background: '#fff', border: '1px solid ' + T.border, borderRadius: '8px', overflow: 'auto' }}>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: T.body, fontSize: 13 }}>
        <thead>
          <tr style={{ background: T.paper, borderBottom: '1px solid ' + T.border, position: 'sticky', top: 0 }}>
            {['Name & issues', 'Country', 'GIA (m²)', 'Asset class', 'EPC', 'α', ''].map((h, i) => (
              <th key={i} style={{
                textAlign: i === 2 || i === 5 ? 'right' : 'left',
                padding: '10px 14px', fontFamily: T.mono, fontSize: 10,
                letterSpacing: '0.12em', textTransform: 'uppercase', color: T.warmGrey, fontWeight: 600,
              }}>{h}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {buildings.map((b, i) => {
            const v = buildingValidations?.find(x => x.b.id === b.id)?.v ?? validateBuilding(b, allBuildings);
            const hasError = v.errors.length > 0;
            const hasWarn = v.warnings.length > 0;
            const hasIssue = hasError || hasWarn;
            const rowBg = hasError ? '#fff8f8' : 'transparent';
            return (
              <tr key={b.id} style={{
                borderBottom: i === buildings.length - 1 ? 'none' : '1px solid ' + T.borderSoft,
                background: rowBg,
              }}>
                <td style={{ padding: '14px 18px', maxWidth: 320 }}>
                  <div style={{ display: 'flex', alignItems: 'flex-start', gap: 8 }}>
                    {hasError && <AlertCircle size={15} color={T.rose} strokeWidth={1.8} style={{ flexShrink: 0, marginTop: 2 }} />}
                    {!hasError && hasWarn && <AlertTriangle size={15} color={T.amber} strokeWidth={1.8} style={{ flexShrink: 0, marginTop: 2 }} />}
                    <div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
                        <span style={{ color: T.ink, fontWeight: 500 }}>{b.name || <em style={{ color: T.warmGreyLight }}>(unnamed)</em>}</span>
                        {b.heatingSystem && (
                          <span style={{ fontFamily: T.mono, fontSize: 9, background: T.successBg, color: T.forest, padding: '2px 6px', borderRadius: 10, border: '1px solid ' + T.forestSoft, cursor: 'default' }}
                            title={HEATING_SYSTEM_OPTIONS.find(o => o.value === b.heatingSystem)?.label}>
                            retrofit data ✓
                          </span>
                        )}
                      </div>
                      {b.address && <div style={{ color: T.warmGrey, fontSize: 12, marginTop: 1 }}>{b.address}</div>}
                      {hasIssue && (
                        <div style={{ marginTop: 6, display: 'flex', flexDirection: 'column', gap: 3 }}>
                          {v.errors.map((e, j) => (
                            <div key={'e' + j} style={{ fontSize: 11, color: T.rose, display: 'flex', alignItems: 'flex-start', gap: 4 }}>
                              <span style={{ flexShrink: 0 }}>✕</span><span>{e}</span>
                            </div>
                          ))}
                          {v.warnings.map((w, j) => (
                            <div key={'w' + j} style={{ fontSize: 11, color: T.amber, display: 'flex', alignItems: 'flex-start', gap: 4 }}>
                              <span style={{ flexShrink: 0 }}>⚠</span><span>{w}</span>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                </td>
                <td style={{ padding: '14px 18px', color: T.inkSoft, verticalAlign: 'top' }}>{b.country ? countryName(b.country) : <em style={{ color: T.warmGreyLight }}>—</em>}</td>
                <td style={{ padding: '14px 18px', textAlign: 'right', color: T.inkSoft, fontFamily: T.mono, fontSize: 12, verticalAlign: 'top' }}>
                  {b.gia ? Number(b.gia).toLocaleString() : '—'}
                </td>
                <td style={{ padding: '14px 18px', color: T.inkSoft, fontSize: 12, verticalAlign: 'top' }}>
                  {b.assetClasses?.length > 0 ? b.assetClasses.map(ac => assetClassName(ac.code) + ' ' + (ac.pct || 0) + '%').join(' / ') : '—'}
                </td>
                <td style={{ padding: '14px 18px', color: T.inkSoft, verticalAlign: 'top' }}>{b.epc || <span style={{ color: T.warmGreyLight }}>—</span>}</td>
                <td style={{ padding: '14px 18px', textAlign: 'right', color: T.inkSoft, fontFamily: T.mono, fontSize: 12, verticalAlign: 'top' }}>
                  {b.alpha != null && b.alpha !== '' ? Number(b.alpha).toFixed(2) : '—'}
                </td>
                <td style={{ padding: '14px 18px', textAlign: 'right', verticalAlign: 'top' }}>
                  <div style={{ display: 'flex', gap: 4, justifyContent: 'flex-end' }}>
                    <button onClick={() => onEdit(b)} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: T.warmGrey, padding: 6 }} title="Edit">
                      <Edit3 size={14} strokeWidth={1.7} />
                    </button>
                    <button onClick={() => onDelete(b)} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: T.warmGrey, padding: 6 }} title="Delete">
                      <Trash2 size={14} strokeWidth={1.7} />
                    </button>
                  </div>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

function handleCsvUpload(e, buildings, setBuildings, push) {
  const file = e.target.files?.[0];
  if (!file) return;
  Papa.parse(file, {
    header: true, skipEmptyLines: true,
    complete: (results) => {
      const rows = results.data;
      if (rows.length === 0) { push('CSV is empty', 'error'); return; }
      const required = ['building_id', 'building_name', 'country_code', 'gia_m2', 'asset_class_pct'];
      // Accept either asset_class_code or asset_class_name
      if (!('asset_class_code' in rows[0]) && !('asset_class_name' in rows[0])) {
        required.push('asset_class_code'); // will trigger the missing column error
      }
      const missing = required.filter(c => !(c in rows[0]));
      if (missing.length > 0) {
        push('Missing required columns: ' + missing.join(', '), 'error');
        return;
      }

      // Group rows by building_id (skip the instructions header row if present)
      const grouped = {};
      rows.forEach(r => {
        const bid = (r.building_id || '').trim();
        if (!bid || bid === '(instructions)') return;
        if (!grouped[bid]) {
          grouped[bid] = {
            id: uid(), name: (r.building_name || '').trim(), address: (r.address || '').trim(),
            country: (r.country_code || '').trim().toUpperCase(),
            gia: parseFloat(r.gia_m2) || 0,
            alpha: parseFloat(r.alpha),
            epc: (r.epc_rating || '').trim(),
            assetClasses: [],
            // Tier-2 retrofit fields
            heatingSystem:      (r.heating_system || '').trim(),            heatingSystem:      (r.heating_system     || '').trim(),
            glazingType:        (r.glazing_type        || '').trim(),
            lightingType:       (r.lighting_type       || '').trim(),
            hasBMS:             r.has_bms    === 'true' || r.has_bms    === 'TRUE'  || r.has_bms    === '1',
            hasSolarPV:         r.has_solar_pv === 'true' || r.has_solar_pv === 'TRUE' || r.has_solar_pv === '1',
            solarPvM2:          parseFloat(r.solar_pv_m2) || 0,
            availableRoofM2:    r.available_roof_m2 !== undefined && r.available_roof_m2 !== '' ? parseFloat(r.available_roof_m2) : null,
            hasEfficientHVAC:   r.has_efficient_hvac === 'true' || r.has_efficient_hvac === 'TRUE' || r.has_efficient_hvac === '1',
            hasDHWHeatPump:     r.has_dhw_heat_pump  === 'true' || r.has_dhw_heat_pump  === 'TRUE' || r.has_dhw_heat_pump  === '1',
            hasRoofInsulation:  r.has_roof_insulation === 'true' || r.has_roof_insulation === 'TRUE' || r.has_roof_insulation === '1',
            hasWallInsulation:  r.has_wall_insulation === 'true' || r.has_wall_insulation === 'TRUE' || r.has_wall_insulation === '1',
            hasAirSealing:      r.has_air_sealing === 'true' || r.has_air_sealing === 'TRUE' || r.has_air_sealing === '1',
          };
          if (isNaN(grouped[bid].alpha)) grouped[bid].alpha = 0.5;
        }
        // Accept both asset_class_code (e.g. "OFF") and asset_class_name (e.g. "Office (OFF)" or "Office")
        let code = (r.asset_class_code || '').trim().toUpperCase();
        if (!code && r.asset_class_name) {
          const nameVal = r.asset_class_name.trim();
          // Try to extract code from parentheses: "Office (OFF)" -> "OFF"
          const parenMatch = nameVal.match(/\(([A-Z]{2,4})\)$/);
          if (parenMatch) {
            code = parenMatch[1];
          } else {
            // Try matching by full name
            const found = CRREM_DATA.asset_classes.find(a =>
              a.name.toLowerCase() === nameVal.toLowerCase() ||
              a.code.toLowerCase() === nameVal.toLowerCase()
            );
            if (found) code = found.code;
          }
        }
        const pct = parseFloat(r.asset_class_pct) || 0;
        if (code && code !== '(INSTRUCTIONS)') grouped[bid].assetClasses.push({ code, pct });
      });

      const imported = Object.values(grouped);

      // ── Cross-row consistency check ──────────────────────────────────────────
      // Fields that must be identical across all rows for the same building_id.
      // asset_class_code and asset_class_pct are intentionally excluded (they vary by design).
      const CONSISTENT_FIELDS = [
        { col: 'building_name',       label: 'name' },
        { col: 'address',             label: 'address' },
        { col: 'country_code',        label: 'country' },
        { col: 'gia_m2',              label: 'GIA' },
        { col: 'alpha',               label: 'alpha' },
        { col: 'epc_rating',          label: 'EPC' },
        { col: 'heating_system',      label: 'heating system' },
        { col: 'glazing_type',        label: 'glazing type' },
        { col: 'lighting_type',       label: 'lighting type' },
        { col: 'has_bms',             label: 'has_bms' },
        { col: 'has_solar_pv',        label: 'has_solar_pv' },
        { col: 'has_efficient_hvac',  label: 'has_efficient_hvac' },
        { col: 'has_dhw_heat_pump',   label: 'has_dhw_heat_pump' },
        { col: 'has_roof_insulation', label: 'has_roof_insulation' },
        { col: 'has_wall_insulation', label: 'has_wall_insulation' },
        { col: 'has_air_sealing',     label: 'has_air_sealing' },
      ];
      // Group raw rows by building_id to check consistency
      const rawByBid = {};
      rows.forEach(r => {
        const bid = (r.building_id || '').trim();
        if (!bid || bid === '(instructions)') return;
        if (!rawByBid[bid]) rawByBid[bid] = [];
        rawByBid[bid].push(r);
      });
      const inconsistentBuildings = [];
      Object.entries(rawByBid).forEach(([bid, bRows]) => {
        if (bRows.length < 2) return;
        const badFields = CONSISTENT_FIELDS.filter(({ col }) => {
          const vals = new Set(bRows.map(r => (r[col] || '').trim().toLowerCase()));
          return vals.size > 1;
        }).map(({ label }) => label);
        if (badFields.length > 0) {
          const name = (bRows[0].building_name || bid).trim();
          inconsistentBuildings.push({ name, fields: badFields });
        }
      });
      // Tag each inconsistent building so validateBuilding can surface it in the Portfolio warnings filter
      const inconsistentByName = {};
      inconsistentBuildings.forEach(({ name, fields }) => { inconsistentByName[name.toLowerCase()] = fields; });
      imported.forEach(b => {
        const fields = inconsistentByName[b.name.toLowerCase()];
        if (fields) b.csvWarnings = fields; else delete b.csvWarnings;
      });

      if (inconsistentBuildings.length > 0) {
        const MAX_NAMES = 4;
        const shown = inconsistentBuildings.slice(0, MAX_NAMES).map(b => b.name);
        const more = inconsistentBuildings.length - MAX_NAMES;
        const nameList = shown.join(', ') + (more > 0 ? ' and ' + more + ' more' : '');
        const fieldList = [...new Set(inconsistentBuildings.flatMap(b => b.fields))].join(', ');
        push(
          inconsistentBuildings.length + ' building' + (inconsistentBuildings.length !== 1 ? 's have' : ' has') +
          ' inconsistent data across rows (' + fieldList + '): ' + nameList +
          '. OR-logic applied for boolean fields; first-row values used for others. Please review your CSV.',
          'warning'
        );
      }

      // Merge: for each imported building, replace if name matches, else append
      const next = [...buildings];
      let added = 0; let replaced = 0;
      imported.forEach(b => {
        const existingIdx = next.findIndex(x => x.name?.toLowerCase() === b.name.toLowerCase());
        if (existingIdx >= 0) { next[existingIdx] = { ...b, id: next[existingIdx].id }; replaced++; }
        else { next.push(b); added++; }
      });
      setBuildings(next);
      push('Imported ' + imported.length + ' building' + (imported.length === 1 ? '' : 's') + ' (' + added + ' new, ' + replaced + ' updated)', 'success');
      e.target.value = '';
    },
    error: () => push('Failed to parse CSV', 'error'),
  });
}

